// Game logic utilities for Hashi (Bridges)

export const ERR_NON_ADJACENT = 'Cannot connect non-adjacent islands';
export const ERR_MAX_PER_PAIR = 'Max 2 bridges per pair';
export const ERR_EXCEED_ISLAND = 'Island would exceed its number';
export const ERR_CROSS = 'Bridges would cross';

export function canonicalKey(a, b) {
  const p1 = { x: a.x, y: a.y };
  const p2 = { x: b.x, y: b.y };
  const first = p1.x < p2.x || (p1.x === p2.x && p1.y <= p2.y) ? p1 : p2;
  const second = first === p1 ? p2 : p1;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function isAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

function isBetween(v, a, b) {
  return v > Math.min(a, b) && v < Math.max(a, b);
}

export function getBridgeSegments(bridges) {
  // returns array of {x1,y1,x2,y2}
  const segs = [];
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    segs.push({ x1, y1, x2, y2, count });
  }
  return segs;
}

export function areAdjacent(islands, from, to) {
  if (!from || !to) return false;
  if (!isAligned(from, to)) return false;
  // No island strictly between them along the line.
  if (from.x === to.x) {
    const x = from.x;
    const y1 = from.y;
    const y2 = to.y;
    for (const isl of islands) {
      if (isl.id === from.id || isl.id === to.id) continue;
      if (isl.x === x && isBetween(isl.y, y1, y2)) return false;
    }
    return true;
  }
  const y = from.y;
  const x1 = from.x;
  const x2 = to.x;
  for (const isl of islands) {
    if (isl.id === from.id || isl.id === to.id) continue;
    if (isl.y === y && isBetween(isl.x, x1, x2)) return false;
  }
  return true;
}

function segmentsCross(segA, segB) {
  // Only consider perpendicular crossings that intersect at a point that is not an endpoint.
  const aVert = segA.x1 === segA.x2;
  const bVert = segB.x1 === segB.x2;
  if (aVert === bVert) return false;

  const vert = aVert ? segA : segB;
  const hori = aVert ? segB : segA;

  const ix = vert.x1;
  const iy = hori.y1;

  // intersection must be strictly inside both segments
  if (!isBetween(ix, hori.x1, hori.x2)) return false;
  if (!isBetween(iy, vert.y1, vert.y2)) return false;

  return true;
}

export function anyCrossing(bridges) {
  const segs = getBridgeSegments(bridges);
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      if (segmentsCross(segs[i], segs[j])) return true;
    }
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + count);
    counts.set(b.id, (counts.get(b.id) ?? 0) + count);
  }
  return counts;
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;
  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const startId = islands[0].id;
  const seen = new Set([startId]);
  const q = [startId];
  while (q.length) {
    const cur = q.shift();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        q.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to || from.id === to.id) return { valid: true, error: null };
  if (!areAdjacent(islands, from, to)) return { valid: false, error: ERR_NON_ADJACENT };

  const key = canonicalKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERR_MAX_PER_PAIR };

  // island counts
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = (counts.get(from.id) ?? 0) + delta;
  const toCount = (counts.get(to.id) ?? 0) + delta;
  if (fromCount > from.value || toCount > to.value) {
    return { valid: false, error: ERR_EXCEED_ISLAND };
  }

  // crossing check with hypothetical update
  const nextBridges = new Map(bridges);
  if (next === 0) nextBridges.delete(key);
  else nextBridges.set(key, next);

  if (anyCrossing(nextBridges)) return { valid: false, error: ERR_CROSS };

  return { valid: true, error: null };
}

export function isVictory(islands, bridges) {
  // Must be satisfied counts, connected, and no crossings.
  if (anyCrossing(bridges)) return false;
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }
  return checkConnectivity(islands, bridges);
}
