import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  canonicalKey,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID_PX = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function buildIslandIndex(islands) {
  const byCoord = new Map();
  for (const isl of islands) byCoord.set(`${isl.x},${isl.y}`, isl);
  return byCoord;
}

function findNextIslandInDirection(islands, fromIsland, dir) {
  // Pick nearest island strictly in direction along row/col.
  const from = fromIsland;
  let best = null;
  let bestDist = Infinity;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      const d = from.x - isl.x;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    } else if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      const d = isl.x - from.x;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    } else if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      const d = from.y - isl.y;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    } else if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      const d = isl.y - from.y;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    }
  }
  return best;
}

function svgLineProps() {
  return {
    stroke: '#0f0',
    strokeWidth: 4,
    strokeLinecap: 'round',
  };
}

function bridgeLinesFor(key, count) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const ax = x1 * GRID_PX;
  const ay = y1 * GRID_PX;
  const bx = x2 * GRID_PX;
  const by = y2 * GRID_PX;

  if (count === 1) {
    return [{ x1: ax, y1: ay, x2: bx, y2: by }];
  }

  // double -> 2 parallel lines, offset perpendicular by 4px
  const off = 5;
  if (ay === by) {
    // horizontal
    return [
      { x1: ax, y1: ay - off, x2: bx, y2: by - off },
      { x1: ax, y1: ay + off, x2: bx, y2: by + off },
    ];
  }
  // vertical
  return [
    { x1: ax - off, y1: ay, x2: bx - off, y2: by },
    { x1: ax + off, y1: ay, x2: bx + off, y2: by },
  ];
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [error, setError] = useState(null);

  const islandsByCoord = useMemo(() => buildIslandIndex(islands), [islands]);
  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  const bridgesRef = useRef(bridges);
  const islandsRef = useRef(islands);
  const selectedRef = useRef(selectedId);
  const cursorRef = useRef(cursorId);

  useEffect(() => {
    bridgesRef.current = bridges;
  }, [bridges]);
  useEffect(() => {
    islandsRef.current = islands;
  }, [islands]);
  useEffect(() => {
    selectedRef.current = selectedId;
  }, [selectedId]);
  useEffect(() => {
    cursorRef.current = cursorId;
  }, [cursorId]);

  function resetAll() {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(0);
  }

  function changePuzzle(nextIndex) {
    setPuzzleIndex(nextIndex);
    // Must reset everything in same state update sequence so next render has 0 lines.
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(0);
  }

  function applyBridgeDelta(from, to, delta) {
    const res = canAddBridge(islands, bridgesRef.current, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return false;
    }

    setBridges((prev) => {
      const next = new Map(prev);
      const key = canonicalKey(from, to);
      const cur = next.get(key) ?? 0;
      const val = cur + delta;
      if (val <= 0) next.delete(key);
      else next.set(key, val);
      return next;
    });
    setError(null);
    setSelectedId(null);
    setCursorId(0);
    return true;
  }

  function cycleBridge(from, to) {
    const key = canonicalKey(from, to);
    const cur = bridgesRef.current.get(key) ?? 0;
    if (cur === 0) return applyBridgeDelta(from, to, 1);
    if (cur === 1) return applyBridgeDelta(from, to, 1);
    // cur === 2 -> remove entirely
    return applyBridgeDelta(from, to, -2);
  }

  function removeBridge(from, to) {
    const key = canonicalKey(from, to);
    const cur = bridgesRef.current.get(key) ?? 0;
    if (cur === 0) {
      setSelectedId(null);
      return;
    }
    // removing is always allowed
    setBridges((prev) => {
      const next = new Map(prev);
      next.delete(key);
      return next;
    });
    setError(null);
    setSelectedId(null);
    setCursorId(0);
  }

  function onIslandMouseDown(e, isl) {
    // right click OR ctrl-click removes bridge if exists between selected and this
    const isRight = e.button === 2;
    const isCtrl = e.ctrlKey;

    if (isRight || isCtrl) {
      e.preventDefault();
      const sel = selectedRef.current;
      if (sel == null || sel === isl.id) {
        setSelectedId(isl.id);
        return;
      }
      const from = islandById(islandsRef.current, sel);
      removeBridge(from, isl);
      return;
    }

    // left click
    const sel = selectedRef.current;
    if (sel == null || sel === isl.id) {
      setSelectedId(isl.id);
      return;
    }

    const from = islandById(islandsRef.current, sel);
    cycleBridge(from, isl);
  }

  useEffect(() => {
    function onKeyDown(e) {
      const curId = cursorRef.current;
      const cur = islandById(islandsRef.current, curId) || islandsRef.current[0];
      if (!cur) return;

      const key = e.key;
      if (key === 'Escape') {
        setSelectedId(null);
        setError(null);
        return;
      }

      if (key === 'ArrowLeft' || key === 'ArrowRight' || key === 'ArrowUp' || key === 'ArrowDown') {
        e.preventDefault();
        const dir =
          key === 'ArrowLeft'
            ? 'left'
            : key === 'ArrowRight'
              ? 'right'
              : key === 'ArrowUp'
                ? 'up'
                : 'down';
        const next = findNextIslandInDirection(islandsRef.current, cur, dir);
        if (next) setCursorId(next.id);
        return;
      }

      if (key === 'Enter') {
        e.preventDefault();
        const sel = selectedRef.current;
        if (sel == null) {
          setSelectedId(cur.id);
          return;
        }
        if (sel === cur.id) {
          setSelectedId(cur.id);
          return;
        }
        const from = islandById(islandsRef.current, sel);
        cycleBridge(from, cur);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);

  const cursorIsland = islandById(islands, cursorId) || islands[0];

  const bridgeLineEls = [];
  for (const [key, count] of bridges.entries()) {
    const lines = bridgeLinesFor(key, count);
    for (let i = 0; i < lines.length; i++) {
      const ln = lines[i];
      bridgeLineEls.push(
        <line key={`${key}:${i}`} {...ln} {...svgLineProps()} />
      );
    }
  }

  return (
    <div style={{ position: 'relative' }}>
      <div style={{ padding: 8 }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => changePuzzle(Number(e.target.value))}
            style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>
        <button
          onClick={resetAll}
          style={{
            marginLeft: 8,
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            cursor: 'pointer',
          }}
        >
          Reset
        </button>
        {error ? <div className="error-message" style={{ marginTop: 8 }}>{error}</div> : null}
        {victory ? <div className="victory-banner" style={{ marginTop: 8, fontWeight: 'bold' }}>SOLVED!</div> : null}
      </div>

      <svg
        width={SVG_W}
        height={SVG_H}
        style={{ display: 'block' }}
        onContextMenu={(e) => e.preventDefault()}
      >
        {bridgeLineEls}

        {/* cursor (must not be a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorIsland.x * GRID_PX - 18}
            y={cursorIsland.y * GRID_PX - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth={2}
            strokeDasharray="4 2"
          />
        ) : null}

        {islands.map((isl) => {
          const px = isl.x * GRID_PX;
          const py = isl.y * GRID_PX;
          const isSelected = selectedId === isl.id;
          return (
            <g key={isl.id}>
              <circle
                cx={px}
                cy={py}
                r={14}
                fill="black"
                stroke={isSelected ? '#0f0' : '#0f0'}
                strokeWidth={isSelected ? 4 : 2}
                onMouseDown={(e) => onIslandMouseDown(e, isl)}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontSize={14}
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {isl.value}
              </text>

              {/* optional current count indicator */}
              <text
                x={px}
                y={py + 28}
                textAnchor="middle"
                fontSize={10}
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none', opacity: 0.7 }}
              >
                {counts.get(isl.id) ?? 0}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>

      {/* prevent default context menu selection issues */}
      <div style={{ padding: 8, opacity: 0.7 }}>
        Mouse: click island A then B to cycle bridge. Right-click or Ctrl+click removes. Keyboard: arrows move cursor, Enter selects/toggles, Esc cancels.
      </div>
    </div>
  );
}
